<script setup lang="ts">import{computed}from'vue';import{Head,useForm}from'@inertiajs/vue3';import AuthenticatedLayout from '@/Layouts/AuthenticatedLayout.vue';import AppButton from '@/Components/UI/AppButton.vue';import AppInput from '@/Components/UI/AppInput.vue';import AppSelect from '@/Components/UI/AppSelect.vue';import AppTextarea from '@/Components/UI/AppTextarea.vue';interface Supplier{id:number;name:string;company_name?:string}interface Product{id:number;name:string;sku:string;unit:string;purchase_price:string}interface Item{product_id:string;purchase_price:string;quantity:string;volume:string;calculation_method:'qty'|'qty_volume'}const props=defineProps<{suppliers:Supplier[];products:Product[]}>();const fresh=():Item=>({product_id:'',purchase_price:'0',quantity:'1',volume:'1',calculation_method:'qty'});const form=useForm<{supplier_id:string;transaction_date:string;supplier_invoice_number:string;purchase_order_number:string;notes:string;items:Item[]}>({supplier_id:'',transaction_date:new Date().toISOString().slice(0,10),supplier_invoice_number:'',purchase_order_number:'',notes:'',items:[fresh()]});const p=(id:string)=>props.products.find(x=>x.id===Number(id));const choose=(i:Item)=>{const x=p(i.product_id);if(x)i.purchase_price=x.purchase_price};const total=(i:Item)=>Number(i.purchase_price)*Number(i.quantity)*(i.calculation_method==='qty_volume'?Number(i.volume):1);const subtotal=computed(()=>form.items.reduce((s,i)=>s+total(i),0));const money=(v:number)=>new Intl.NumberFormat('id-ID',{style:'currency',currency:'IDR',maximumFractionDigits:0}).format(v);</script><template><Head title="Catat Barang Masuk"/><AuthenticatedLayout><template #breadcrumb>Transaksi / Barang Masuk / Baru</template><form @submit.prevent="form.post(route('incoming.store'))"><div class="mb-6 flex items-end justify-between"><div><h1 class="page-title">Catat Barang Masuk</h1><p class="page-subtitle">Simpan sebagai draft, lalu finalisasi dari daftar transaksi.</p></div><AppButton type="submit" :disabled="form.processing">Simpan Draft</AppButton></div><section class="panel p-5"><div class="grid gap-4 md:grid-cols-2"><label><span class="label">Supplier *</span><AppSelect v-model="form.supplier_id" required><option value="">Pilih supplier</option><option v-for="s in suppliers" :key="s.id" :value="s.id">{{s.company_name||s.name}}</option></AppSelect></label><label><span class="label">Tanggal *</span><AppInput v-model="form.transaction_date" type="date" required/></label><label><span class="label">Nomor Faktur Supplier</span><AppInput v-model="form.supplier_invoice_number"/></label><label><span class="label">Nomor Purchase Order</span><AppInput v-model="form.purchase_order_number"/></label></div></section><section class="panel mt-5"><div class="border-b px-5 py-4 font-bold">Detail Barang</div><div class="table-wrap"><table class="data-table min-w-[850px]"><thead><tr><th>Barang</th><th>Harga Beli</th><th>Qty</th><th>Volume</th><th>Metode</th><th>Satuan</th><th>Total</th><th></th></tr></thead><tbody><tr v-for="(item,i) in form.items" :key="i"><td><AppSelect v-model="item.product_id" required @update:model-value="choose(item)"><option value="">Pilih barang</option><option v-for="product in products" :key="product.id" :value="product.id">{{product.name}} ({{product.sku}})</option></AppSelect></td><td><AppInput v-model="item.purchase_price" type="number" min="1"/></td><td><AppInput v-model="item.quantity" type="number" min="0.0001" step="0.0001"/></td><td><AppInput v-model="item.volume" type="number" min="0.0001" step="0.0001" :disabled="item.calculation_method==='qty'"/></td><td><AppSelect v-model="item.calculation_method"><option value="qty">Qty</option><option value="qty_volume">Qty × Volume</option></AppSelect></td><td>{{p(item.product_id)?.unit??'-'}}</td><td class="font-semibold">{{money(total(item))}}</td><td><button type="button" class="text-red-600" @click="form.items.length>1&&form.items.splice(i,1)">⌫</button></td></tr></tbody></table></div><button type="button" class="m-4 rounded border border-sky-300 px-3 py-2 text-sm font-semibold text-sky-600" @click="form.items.push(fresh())">＋ Tambah Barang</button></section><section class="panel mt-5 p-5"><div class="grid gap-5 md:grid-cols-2"><label><span class="label">Catatan</span><AppTextarea v-model="form.notes"/></label><div class="flex items-center justify-between rounded-xl bg-slate-50 p-5"><span class="font-bold">TOTAL BARANG MASUK</span><strong class="text-2xl text-sky-600">{{money(subtotal)}}</strong></div></div><p v-if="Object.keys(form.errors).length" class="mt-3 text-sm text-red-600">{{Object.values(form.errors)[0]}}</p></section></form></AuthenticatedLayout></template>
